    #[inline]
    pub fn prepared_random_prime_with_msb_set<T, const N: usize>(&mut self) -> BigUInt<T, N>
    where T: TraitsBigUInt<T>
    {
        self.get_prepared_prime_number(T::size_in_bytes() as usize * N)
    }

